#!/bin/bash
# Platform run.sh for H010_ns_to_s_xattn.
# OneTrans NS→S bidirectional cross-attention 직접 구현 (paper-grade).
# H007 (1-token candidate xattn) 의 N_NS-token 일반화.
# H008 anchor (DCN-V2 fusion) 위 single mutation stacking.
# 통합 위치: fusion 이전, NS dimension 변경 없음 → H009 위치 충돌 회피.
# §17.4 target_attention 재진입정당화 — paper-grade source (OneTrans).
# §10.9 attn entropy active 적용 (threshold 0.95 × log(384) ≈ 5.65).
# §18 inference 인프라 룰 inherit.
# Generated by skills/_helpers/build_cloud_package.py — do not hand-edit on platform.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
export PYTHONPATH="${SCRIPT_DIR}:${PYTHONPATH:-}"

# ---------------------------------------------------------------------------
# Platform must set TRAIN_DATA_PATH and TRAIN_CKPT_PATH. Other paths derive.
# ---------------------------------------------------------------------------
: "${TRAIN_DATA_PATH:?TRAIN_DATA_PATH not set by platform}"
: "${TRAIN_CKPT_PATH:?TRAIN_CKPT_PATH not set by platform}"
: "${TRAIN_LOG_PATH:=${TRAIN_CKPT_PATH}/logs}"
: "${TRAIN_TF_EVENTS_PATH:=${TRAIN_CKPT_PATH}/tf_events}"
: "${TRAIN_WORK_PATH:=${TRAIN_CKPT_PATH}/work}"
mkdir -p "${TRAIN_CKPT_PATH}" "${TRAIN_LOG_PATH}" "${TRAIN_TF_EVENTS_PATH}" "${TRAIN_WORK_PATH}"
export TRAIN_LOG_PATH TRAIN_TF_EVENTS_PATH

echo "[run.sh] DATA=${TRAIN_DATA_PATH}"
echo "[run.sh] CKPT=${TRAIN_CKPT_PATH}"
echo "[run.sh] mode=ns-to-s-xattn (paper-grade NS→S bidirectional + H008 DCN-V2 anchor)"

# ---------------------------------------------------------------------------
# Train (H008 envelope + H008 mechanism + H010 NS→S xattn).
# Diff vs H008/upload/run.sh:
#   --use_ns_to_s_xattn               H010 NEW: NSToSCrossAttention 활성
#   --ns_xattn_num_heads 4            H010 NEW: default = num_heads
#   --log_attn_entropy                H010 NEW: §10.9 룰 active
# H008 mechanism flags (--fusion_type dcn_v2 --dcn_v2_num_layers 2 --dcn_v2_rank 8) 그대로 유지.
# ---------------------------------------------------------------------------
python3 -u "${SCRIPT_DIR}/train.py" \
    --num_epochs 10 \
    --patience 3 \
    --seed 42 \
    --ns_tokenizer_type rankmixer \
    --user_ns_tokens 5 \
    --item_ns_tokens 2 \
    --num_queries 2 \
    --ns_groups_json "" \
    --emb_skip_threshold 1000000 \
    --num_workers 2 \
    --buffer_batches 4 \
    --train_ratio 0.3 \
    --seq_max_lens "seq_a:64,seq_b:64,seq_c:128,seq_d:128" \
    --use_label_time_split \
    --oof_user_ratio 0.1 \
    --split_seed 42 \
    --fusion_type dcn_v2 \
    --dcn_v2_num_layers 2 \
    --dcn_v2_rank 8 \
    --use_ns_to_s_xattn \
    --ns_xattn_num_heads 4 \
    --log_attn_entropy \
    "$@"

echo "[run.sh] training complete (ns-to-s-xattn); metrics at ${TRAIN_CKPT_PATH}/metrics.json"
